def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 6):
            term = ((-1) ** j) * (ratio ** j) / j
            if j % 2 == 0:
                term *= 1.5
            else:
                term *= 0.75
            score += term
        if capacity < item * 1.2:
            score *= 3
            for k in range(1, 4):
                score += ((-1) ** k) * (ratio ** (k+5)) / (k+5)
        elif capacity < item * 2:
            score *= 1.5
            for k in range(3):
                score += np.sin(ratio * (k+1)) / (k+1)
        elif capacity > item * 4:
            score /= 3
            for k in range(2, 5):
                score -= np.log1p(ratio * k) / (k+1)
        else:
            for k in range(1, 3):
                score += (ratio ** k) * np.cos(k * ratio) / (k+2)
        if np.isclose(score, 0):
            priorities[i] = np.inf
        else:
            priorities[i] = -score
    return priorities
